#nullable enable // autogenerated

using MVZ2Logic;
using MVZ2Logic.Entities;
using MVZ2Logic.Definitions;
using MVZ2Logic.Definitions;
using MVZ2Logic.Options;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.vSync)]
    public class VSyncOptionToggle : OptionToggleDefinition
    {
        public VSyncOptionToggle(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool ShouldEnable(IOptionContext context)
        {
            if (Global.Game.IsMobile())
                return false;
            return base.ShouldEnable(context);
        }
        public override bool GetValue(IOptionContext context)
        {
            return Global.Options.GetVSync();
        }

        public override void OnValueChanged(IOptionContext context, bool value)
        {
            Global.Options.SetVSync(value);
            Global.Options.SaveOptions();
        }
    }
}
